errorMessage:
{{ 
  (() => {
    const cpf = InputCPF.text.replace(/\D/g, "");
    if (cpf.length === 11 && SelectCheckCPF.data.length > 0 && SelectCheckCPF.data[0].prop001_id != TableTutor.selectedRow?.prop001_id) {
      return "Este CPF já pertence ao tutor: " + SelectCheckCPF.data[0].prop001_nome;
    }
    return "CPF inválido";
  })()
}}

validation:
{{
  (() => {
    let cpf = InputCPF.text.replace(/\D/g, "");
    if (cpf.length !== 11 || !!cpf.match(/(\d)\1{10}/)) return false;
    let cpfs = cpf.split("");
    let v1 = 0, v2 = 0;
    for (let i = 0; i < 9; i++) {
      v1 += cpfs[i] * (10 - i);
      v2 += cpfs[i] * (11 - i);
    }
    v1 = (v1 * 10) % 11 % 10;
    v2 = ((v2 + v1 * 2) * 10) % 11 % 10;
    return v1 == cpfs[9] && v2 == cpfs[10];
  })()
}}
